var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나이엘, 장작 준비는 다 끝났어.","JPN":"ナイエル、薪は組み終わったよ。","ENG":"Naielle, the firewood's all ready.","TWN":"奈爾，木柴都準備好了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으, 으응…….","JPN":"う、うん……","ENG":"O-okay...","TWN":"呃，嗯嗯……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"내일, 캠프파이어에 점화하기 전까지는 쌓아 놓은 장작 근처에 가까이 가지 말도록 교내 방송도 마쳤습니다.","JPN":"明日の本番まで、組んだ薪に近づかないように、全校生徒には注意喚起の校内放送もしておきました。","ENG":"I've notified the student body not to go near the stacked firewood until it gets lit tomorrow.","TWN":"我也已經廣播通知大家，在明天升起營火前不要靠近堆放木柴的地方。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"설마, 정말로 준비가 하나도 안 되어 있을 줄은 몰랐네.","JPN":"まさか、まったく準備していなかったなんて驚きだよ。","ENG":"Oh, I didn't think it was THIS unprepared.","TWN":"真是沒想到，你們竟然真的毫無準備。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"그래도 모두가 도와준 덕분에 어떻게든 끝낼 수 있을 것 같아.","JPN":"でも、みんなが協力したおかげで、なんとかなりそうだね。","ENG":"At least we got it done with everyone's help.","TWN":"幸好大家一起下來幫忙，總算是關關難過關關過。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐야!? 누가 도와달라고 말이나 했어? 다들 이런 걸로 생색내지 말라구!","JPN":"わ、悪かったわよ……\\n","ENG":"W-what?! I didn't ask for your help! So don't rub it in, okay?","TWN":"怎，怎樣！？我有叫你們幫忙嗎？在那邊囂張什麼！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아무튼 남은건 점화용 토치인가. 나이엘, 토치 준비는 되었겠지?","JPN":"後は点火用のトーチだな。ナイエル、準備の方は……","ENG":"Anyway, the only thing left is the blowtorch. Naielle, did you prepare one?","TWN":"總之現在就只差點火的火把。奈爾，你有準備火把吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"토치? 아, 그게 어디 갔더라…….","JPN":"トーチ？　え？　あ、そうだった……","ENG":"A blowtorch? Oh, um, where did I put the blowtorch...","TWN":"火把？呃，那個，我放哪啦……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"어이, 설마 그것도 깜빡한거야?","JPN":"おいおい。それも忘れていたのか？","ENG":"You didn't forget that too, did you?","TWN":"哀，你該不會連火把都沒準備吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"괘, 괜찮아! 불을 붙이는 것 뿐이잖아? 그 정도는 간단하다구!","JPN":"だ、大丈夫！　火を点けるだけでしょ？　そんなの簡単よ！","ENG":"I-it's fine! It's just used to light the campfire, right? I can do that!","TWN":"沒，沒問題啦！不過就是點火而已，那還不簡單！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘씨?","JPN":"ナイエルさん？","ENG":"Naielle?","TWN":"奈爾？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"다들 잘 봐, 마른 장작에 불 붙이는 것 정도는 이렇게!","JPN":"見てなさい。キャンプファイヤーの火ぐらいこれで！","ENG":"Look, lighting dry wood on fire is as simple as that!","TWN":"你們看好囉，在乾柴上點火，輕而易舉！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"바보야! 지금 불을 붙이면 어떡해! 후야제는 내일 저녁에 시작한다고!","JPN":"バカ！　今、火を点けてどうする。本番は明日だぞ！","ENG":"You fool! Why would you light in on fire right now?! The post-festival party starts tomorrow!","TWN":"你這傻瓜！現在還不能點火！慶功宴是在明天晚上！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Ah...","TWN":"呃……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나는 쓰레기……. 학원제 준비도 똑바로 못하고……. 불 붙이는 것도 제대로 못하는 쓰레기…….","JPN":"私はゴミ……\\n準備すらまともに出来ず、間違えて火を点けちゃうゴミ……","ENG":"I'm just garbage... I can't do anything right... I'm garbage that can't even light a fire properly...","TWN":"我這個垃圾……學園祭也準備不好……連點個火都會搞砸的垃圾……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"불에도 안타고…… 재활용도 안 되는 멍청한 쓰레기…….","JPN":"燃えないし……リサイクルもできないバカなゴミ……","ENG":"I'm a stupid piece of garbage... that can't be burned or recycled...","TWN":"我是無法焚燒……也無法回收再利用的垃圾……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"그렇지 않아요, 실수는 누구나 하는 거니까요.","JPN":"間違いは誰にでもありますよ、ナイエルさん。","ENG":"That's not true. Everyone makes mistakes.","TWN":"不是的，人非聖賢，誰能無過。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"그리고 나이엘 양이 누구보다 축제에 진심이라는 건 제가 가장 잘 아는 걸요.","JPN":"ナイエルさんが誰よりも学園祭に本気だったということは、\\n僕が一番わかっています。","ENG":"And I know how much you care about the festival, Naielle.","TWN":"而且我很清楚，你比任何人都還要認真看待學園祭。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"왜냐하면 나이엘 양과 마찬가지로 저도 올해 학년 대표니까요.","JPN":"ナイエルさんと同じく、僕も学年代表ですから。","ENG":"That's because, like you, I'm also this year's student representative.","TWN":"因為我和你一樣，都是今年的學生代表。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"타피르 선배…….","JPN":"タピル先輩……","ENG":"Tapir...","TWN":"達爾前輩……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"응. 기운 내, 나이엘.","JPN":"そうだよ、ナイエル。元気出して。","ENG":"Yeah, cheer up, Naielle.","TWN":"嗯，加油，奈爾。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"맞아, 다행히 예비 장작도 있으니까, 내일 캠프파이어는 문제 없을 거야.","JPN":"そうそう、幸いにも予備の薪はあるんだし、\\n明日の本番までにまた薪を組めばいいだけだよ。","ENG":"She's right. We have some leftover firewood too, so tomorrow's campfire won't be an issue.","TWN":"對啊，幸好還有備用的木柴，明天的營火不會有問題的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"정말이지. 그나마 불이 제대로 붙는 건 확인했으니까 일단 다행이라고 해둘까?","JPN":"まったく。だが、立派に火が点くことが確認できたから良しとするか。","ENG":"For what it's worth, let's just say that we discovered that the firewood does, in fact, catch fire.","TWN":"是啊，至少已經確認點火是沒問題的，算是有收穫吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그래……?","JPN":"そう……？","ENG":"Really...?","TWN":"是嗎……？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아하하핫! 역시 대단한 불꽃이지? 좀 더 칭찬해도 좋다구?","JPN":"アハハハッ！　やっぱり！　素晴らしい炎でしょ？\\nもっと褒めてもいいのよ？","ENG":"Ah ha ha hah! That was an awesome fire, wasn't it? Praise me more!","TWN":"哈哈哈哈！火很旺吧？你們可以盡情誇獎我。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇게 금방 기고만장해지는 건 좋지 못한 버릇이로군요, 나이엘 양.","JPN":"調子に乗ってはいけませんよ、ナイエルさん。","ENG":"It's not a good habit to become overly self-confident, Naielle.","TWN":"這麼容易就得意忘形不太好喔，奈爾。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으극…….","JPN":"うぐ……","ENG":"Urgh...","TWN":"嗚嗚……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데…… 다들 오늘 뭔가 이상한 일 없었어?","JPN":"ところで……みんな、今日は何か変なことが起きなかった？","ENG":"Other than that... didn't you guys notice anything odd today?","TWN":"不過……大家今天沒發生什麼怪事嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"이상한 일이라니? 무슨 말이야, 미나?","JPN":"変なことって？　どういう意味なの、ミナ？","ENG":"Odd? What do you mean, Mina?","TWN":"發生怪事？那是什麼意思，米娜？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그게, 누군가 수영장에 기름통을 가져다 놓았거든. 거기서 기름이 악취의 원인이었어.","JPN":"それがね。誰かがプールに油缶を隠していたんだ。\\nそこから漏れた油が悪臭の原因だったの。","ENG":"Well, someone hid an oil barrel near the pool. That was where the stench was coming from.","TWN":"有人把汽油桶放在游泳池那裡，那就是發臭的原因。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"맞아. 미나가 없었으면, 나 혼자서는…….","JPN":"そうそう。ミナがいなかったら、私一人だと対処できなかったよ。","ENG":"Yeah. Without Mina, I couldn't have done it...","TWN":"對啊，要不是有米娜，光靠我自記……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"그러고보니…… 사진부에서도 비슷한 일이 있었어. 결국 내일 전시는 중단됐고.","JPN":"そういえば……写真部でも似たようなことがあったな。\\n結局、展示は中止になっちゃった。","ENG":"Now that you mention it... Something similar happened at the photography club too. Tomorrow's exhibition ultimately got canceled.","TWN":"這麼說來……攝影部也有發生類似的情況，導致明天的展出取消。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"우연이라고 하기엔 이상하군요. 연극부도 사정이 생겨서 연극이 취소되었습니다.","JPN":"偶然というにはおかしいですね。\\n演劇部も事情があり、演劇は中止になりました。","ENG":"It is certainly odd to call all this a mere coincidence. The theater club's play was also canceled due to circumstances.","TWN":"感覺事有蹊蹺，戲劇部也是因為一些事決定取消演出。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"잠깐, 그렇다는 말은 누군가가 학원제를 방해하려고 했다는 건가요?","JPN":"待ってください、つまり誰かが学園祭を妨害しているということですか？","ENG":"Wait a minute. Does that mean that someone's trying to sabotage our festival tomorrow?","TWN":"意思是，有人企圖想破壞學園祭嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"루루는 실행위원장이니까, 학원제를 감독하고 있었지? 수상해 보이는 사람은 없었어?","JPN":"ルルは実行委員長だから、学園内を見回っていたんだよね？\\n怪しい人を見かけたりとかはなかったの？","ENG":"Lulu, you're the head of the executive committee, so you're overseeing the whole festival, right? Did you see anyone looking suspicious?","TWN":"魯魯是執行委員長，你有在監督吧？有看到什麼可疑人士嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아니. 특별히 수상한 사람은 보지 못했어. 하지만 가능성이 완전히 없다고도 말할 수 없겠군.","JPN":"いいや。目立って不審人物を見かけたりなどは無かった。\\nただ、可能性がないとは言い切れない。","ENG":"No. I haven't seen anyone who looked suspicious. But I also can't rule out sabotage as a possibility.","TWN":"沒有，沒看到什麼可疑人士，但我也無法保證沒這個可能性。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐야, 다들 왜 그렇게 진지한 건데?","JPN":"なになに？　みんな真剣な顔してどうしちゃったの？","ENG":"Huh? Why's everyone so serious all of a sudden?","TWN":"唉唷～大家幹嘛這麼嚴肅？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어차피 이미 지난 일이니까 신경 쓸 필요 없잖아? 어쨌든 지금은 모두 내일 있을 학원제를 즐길 생각을 해야지! ","JPN":"もう過ぎたことだし気にしなくていいんじゃない？\\nとにかく今は、明日の学園祭をみんなが楽しめるようにしないと！","ENG":"We shouldn't care so much about what's already been done, right? We should only be looking forward to enjoying the festival tomorrow!","TWN":"反正都已經處理好啦，不用想太多啦。現在只需要想著我們明天要嗨翻學園祭！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요. 나이엘 양의 말이 맞습니다.","JPN":"そうですね、ナイエルさんの言うとおりです。","ENG":"Yes. Naielle is right.","TWN":"是啊，奈爾說的沒錯。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"불가피하게 행사가 중지된 동아리가 있는 건 유감이지만, 진상 규명은 나중에 하도록 하죠.","JPN":"中止になってしまった部は残念ですが、真相の究明は後日にしましょう。","ENG":"I am sorry for the clubs that can't participate due to inevitable circumstances, but we will get to the bottom of this later.","TWN":"雖然很遺憾某些社團因為特殊因素而取消活動，但等結束後再查明原因吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"지금은 학원제가 무사히 성공할 수 있도록 모두 최선을 다 하도록 해요.","JPN":"今は学園祭が成功するように少しでも準備を進めないと……","ENG":"Right now, we should focus on ensuring that the festival goes without a hitch.","TWN":"現在的重點是要努力讓學園祭可以順利進行。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그럼 이걸로 학원제 준비를 모두 마치도록 하죠. 여러분, 수고 많으셨습니다.","JPN":"それでは、学園祭の準備はここまでです。皆様、お疲れ様でした。","ENG":"Good work, everyone. We shall end the preparations for tomorrow here.","TWN":"那學園祭的預備就到此結束，大家都辛苦囉。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"드디어 내일이 학원제 당일이네.","JPN":"明日はいよいよ本番ね。","ENG":"The festival's just a day away.","TWN":"明天終於就是學園祭了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"응, 열심히 준비했잖아. 모두 후회없는 학원제를 만들자!","JPN":"うん。せっかく準備してるんだもの。いい学園祭にしましょう。","ENG":"Yeah, and we worked hard for it. So let's make it the best festival ever!","TWN":"嗯，我們準備得那麼認真，創造一個沒有遺憾的學園祭吧！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"무슨 일 있어, 미나?","JPN":"どうかしたのか、ミナ？","ENG":"Something the matter, Mina?","TWN":"米娜，你怎麼了？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"를르슈…… 으음, 왠지 전에도 이런 일이 있었던 것 같은 느낌이 들어서…….","JPN":"ルルーシュ……ううん。\\nなんだか、前にもこんなことがあったような気がして……","ENG":"Lelouch... Um, I just feel like I've experienced something like this before...","TWN":"魯路修……我總覺得以前也發生過同樣的事……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"으음? 그거 혹시 데자뷰 같은 거 아니야? 만화에서 봤어!","JPN":"それって、デジャヴじゃない？","ENG":"Hmm? Are you talking about deja vu? I read about it in comics!","TWN":"蛤？這是所謂的既視感嗎？我在漫畫裡有看過！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"데자뷰라, 확실히 그럴지도 모르겠네.","JPN":"デジャヴか、そうなのかも。","ENG":"Deja vu? Maybe it's that.","TWN":"既視感嗎？確實有可能。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아아,나도 만화 속 주인공처럼 타임머신 같은 걸 쓸 수 있었으면 좋았을 텐데.","JPN":"あ～あ、私も漫画の主人公のようにタイムマシンとか使えたらよかったのに。","ENG":"Ahh, I wish I could travel through time like they do in comic books.","TWN":"嗚～真希望我也可以像漫畫裡的主角一樣，搭時光機回到過去。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼 오늘 실수도 안하고, 학원제 준비도 더 완벽하게 할 수 있었을 거 아니야.","JPN":"それならミスもしないで、学園祭の準備ももっと完璧に出来たのになぁ。","ENG":"Then, I wouldn't have made any mistakes and the festival preparation would have been even more perfect.","TWN":"那我就不會犯下今天的錯誤，也可以完美地預備學園祭。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"그렇네요. 정말 그럴 수 있으면 좋을 텐데.","JPN":"なるほど。それは、そうかもしれませんね。","ENG":"Yes. That certainly would be nice.","TWN":"對欸，要是真的可以回到過去就好了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아아~ 아쉬워라. 눈을 떴을 때, 오늘로 되돌아 가면 좋을 텐데.","JPN":"あ～あ。今日がもう一回くればいいのに。","ENG":"Oh, well. I wish I could just close my eyes and go back in time to this morning.","TWN":"嗚～真可惜。好希望睜開眼睛後就可以回到今天。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};